using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: EF9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Restore the old name so existing
            // documents are still found.
            b.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF9 maps the key property directly to the JSON
            // "id" field. EF8 stored the key in an "Id" JSON property and
            // synthesized the Cosmos "id" as "{Discriminator}|{Key}".
            // Keep "Id" mapped to its original JSON property name, and add a
            // shadow property that preserves the old "id" format.
            b.Property(e => e.Id).ToJsonProperty("Id");
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: HasIndex is not supported by the Cosmos
            // provider and now throws in EF9 (was silently ignored in EF8).
            // REMOVED: b.HasIndex(b => b.Name);
        });
    }
}

// Generates Cosmos "id" values in the legacy "{Discriminator}|{Key}" format.
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.GetDiscriminatorValue()}|{entry.Property("Id").CurrentValue}";
}

